args.query:
SELECT Symbol, "Company Description" AS company_name
FROM stockinfo
WHERE "Market Category" = 'S' AND (ETF IS NULL OR ETF <> 'Y') AND ("Test Issue" IS NULL OR "Test Issue" <> 'Y');

